  // mux
  //----------------------------------------------------------------
  always @*
    begin : mux
      muxed_new_block = 128'h0;
      muxed_round_nr  = 4'h0;
      muxed_ready     = 1'b0;
      muxed_sboxw     = 32'h0;
      enc_next        = 1'b0;
      dec_next        = 1'b0;
      init_state      = 1'b0;

